#define D_IMPLEMENTATION
#include"d.h"

#define DEVENTS_IMPLEMENTATION
#include"devents.h"

#define D_PLATFORM_IMPLEMENTATION
#include"platform/ndsd.h"

#include<stdio.h>
#include<nds.h>


/* This test finds the time that
 *  D_SurfCopyScaleRot() takes to run at
 *  different rotations.
 *
 * At the time of making this test, using the
 *  melonDS emulator 1.0 on an old laptop, these
 *  were the results:
 *  Test 0 874 ticks
 *  Test 1 1976 ticks
 *  Test 2 1976 ticks
 *  Test 3 4321 ticks
 *  Test 4 8518 ticks
 *  Test 5 13713 ticks
 *
 * After optimising D_SurfCopyScaleRot(), these
 *  are the results:
 *  Test 0 879 ticks
 *  Test 1 945 ticks
 *  Test 2 919 ticks
 *  Test 3 1221 ticks
 *  Test 4 747 ticks
 *  Test 5 1307 ticks
 *
 * This is the nds version of the test, the
 *  function seems to run slower on nds.
 *
 * This test uses the standard library to print
 *  the results and libnds to time the function.
 */


const int timer = 1;
extern char mouseData[];
const int mouseDataW = 37;
const int mouseDataH = 24;

int speedTest(D_Surf * img, D_Surf * out, D_Rect * rect, D_Point * centre, D_double deg){

    int static testNumber = 0;

    u16 startTime = 0;
    u16 endTime = 0;

    startTime = timerTick(timer);
    D_SurfCopyScaleRot(img, D_NULL, out, rect, centre, deg, 0, 0);
    endTime = timerTick(timer);

    printf("TestNo: %d\ntime: %dticks deg: %f\n", testNumber, endTime - startTime, deg);

    testNumber++;

    return 0;
};

int main(){


    D_Surf * out = D_GetOutSurf(50, 50, 640, 480, "D_SurfCopyScaleRot() speed test", 0);
    D_Surf * img = D_CreateSurfFrom(mouseDataW, mouseDataH, 0, D_NULL, D_FindPixFormat(0xFF, 0xFF00, 0xFF0000, 0xFF000000, 32), mouseData);
    D_Rect rect = {10, 10, mouseDataW, mouseDataH};
    D_Point centre = {mouseDataW / 2, mouseDataH / 2};

    consoleDemoInit();

    timerStart(timer, ClockDivider_1024, 0, D_NULL);


    speedTest(img, out, &rect, &centre, 0);

    rect.x += rect.w + 20;
    speedTest(img, out, &rect, &centre, 30);

    rect.x += rect.w + 20;
    speedTest(img, out, &rect, &centre, 30.75);

    rect.y += rect.h + 20;
    rect.x = 25;
    speedTest(img, out, &rect, &centre, 90);

    rect.x += rect.w + 20;
    speedTest(img, out, &rect, &centre, 225);

    rect.x += rect.w + 20;
    speedTest(img, out, &rect, &centre, 359);

    D_FlipOutSurf(out);

    printf("Done\n");
    while(1);


    D_FreeSurf(img);
    img = D_NULL;

    D_FreeOutSurf(out);
    out = D_NULL;

    return 0;
};

